      "source": "<!-- 削除確認モーダル -->\r\n<div class=\"modal-bg\" id=\"delModal\">\r\n  <div class=\"modal\">\r\n    <h3>🗑️ 削除しますか？</h3>\r\n    <p id=\"delMsg\" style=\"font-size:13px;color:#555;\"></p>\r\n    <div class=\"modal-btns\">\r\n      <button class=\"btn-cancel\" onclick=\"closeModal()\">キャンセル</button>\r\n      <button style=\"padding:8px 18px;border:none;border-radius:8px;background:var(--red);color:#fff;font-size:13px;font-weight:bold;cursor:pointer;\" onclick=\"confirmDelete()\">削除する</button>\r\n    </div>\r\n  </div>\r\n</div>\r\n"
