      "source": "<div class=\"nav\">\r\n  <h1>📊 先生画面</h1>\r\n  <button class=\"tab active\" onclick=\"switchTab('status', this)\">📡 授業スタート</button>\r\n  <button class=\"tab\" onclick=\"switchTab('records', this)\">📝 記録・所見・評定</button>\r\n  <button class=\"tab\" onclick=\"switchTab('curriculum', this)\">📚 教科・単元設定</button>\r\n  <button class=\"tab\" onclick=\"switchTab('roster', this)\">👥 名簿</button>\r\n  <button class=\"tab\" onclick=\"switchTab('help', this)\">🚀 使い方</button>\r\n  <button class=\"tab\" onclick=\"switchTab('prompts', this)\">⚙️ 設定・Aiプロンプト</button>\r\n  <button class=\"tab\" onclick=\"switchTab('logs', this)\">🪵 ログ</button>\r\n</div>\r\n<div class=\"build-bar\" id=\"buildBar\">build: 読み込み中…</div>\r\n"
