      "name": "teacher_polyfills",
      "type": "HTML",
      "source": "<script>\r\n(function(){\r\n  if (!Array.prototype.find) {\r\n    Array.prototype.find = function(predicate, thisArg) {\r\n      if (this == null) throw new TypeError('Array.prototype.find called on null or undefined');\r\n      if (typeof predicate !== 'function') throw new TypeError('predicate must be a function');\r\n      var list = Object(this);\r\n      var length = list.length >>> 0;\r\n      for (var i = 0; i < length; i += 1) {\r\n        var value = list[i];\r\n        if (predicate.call(thisArg, value, i, list)) return value;\r\n      }\r\n      return void 0;\r\n    };\r\n  }\r\n\r\n  if (!Array.prototype.includes) {\r\n    Array.prototype.includes = function(search, start) {\r\n      var list = Object(this);\r\n      var length = list.length >>> 0;\r\n      if (!length) return false;\r\n      var index = start | 0;\r\n      if (index < 0) index = Math.max(length + index, 0);\r\n      for (; index < length; index += 1) {\r\n        if (list[index] === search || (search !== search && list[index] !== list[index])) return true;\r\n      }\r\n      return false;\r\n    };\r\n  }\r\n\r\n  if (!String.prototype.includes) {\r\n    String.prototype.includes = function(search, start) {\r\n      return this.indexOf(search, start || 0) !== -1;\r\n    };\r\n  }\r\n\r\n  if (!Array.from) {\r\n    Array.from = function(source) {\r\n      if (!source) return [];\r\n      var out = [];\r\n      var length = typeof source.length === 'number' ? source.length : 0;\r\n      for (var i = 0; i < length; i += 1) out.push(source[i]);\r\n      return out;\r\n    };\r\n  }\r\n\r\n  if (!Object.assign) {\r\n    Object.assign = function(target) {\r\n      if (target == null) throw new TypeError('Cannot convert undefined or null to object');\r\n      var to = Object(target);\r\n      for (var i = 1; i < arguments.length; i += 1) {\r\n        var source = arguments[i];\r\n        if (source == null) continue;\r\n        for (var key in source) {\r\n          if (Object.prototype.hasOwnProperty.call(source, key)) {\r\n            to[key] = source[key];\r\n          }\r\n        }\r\n      }\r\n      return to;\r\n    };\r\n  }\r\n\r\n  if (typeof window.requestAnimationFrame !== 'function') {\r\n    window.requestAnimationFrame = function(callback) {\r\n      return window.setTimeout(function(){ callback(Date.now ? Date.now() : new Date().getTime()); }, 16);\r\n    };\r\n  }\r\n\r\n  if (typeof window.requestIdleCallback !== 'function') {\r\n    window.requestIdleCallback = function(callback) {\r\n      return window.setTimeout(function(){\r\n        callback({\r\n          didTimeout: false,\r\n          timeRemaining: function(){ return 0; }\r\n        });\r\n      }, 1);\r\n    };\r\n  }\r\n\r\n  if (typeof window.Map !== 'function') {\r\n    window.Map = function(iterable) {\r\n      this._keys = [];\r\n      this._values = [];\r\n      if (iterable && typeof iterable.length === 'number') {\r\n        for (var i = 0; i < iterable.length; i += 1) {\r\n          this.set(iterable[i][0], iterable[i][1]);\r\n        }\r\n      }\r\n    };\r\n    window.Map.prototype.set = function(key, value) {\r\n      var index = this._keys.indexOf(key);\r\n      if (index === -1) {\r\n        this._keys.push(key);\r\n        this._values.push(value);\r\n      } else {\r\n        this._values[index] = value;\r\n      }\r\n      return this;\r\n    };\r\n    window.Map.prototype.get = function(key) {\r\n      var index = this._keys.indexOf(key);\r\n      return index === -1 ? void 0 : this._values[index];\r\n    };\r\n    window.Map.prototype.has = function(key) {\r\n      return this._keys.indexOf(key) !== -1;\r\n    };\r\n    window.Map.prototype.values = function() {\r\n      return this._values.slice();\r\n    };\r\n  }\r\n\r\n  if (typeof window.Set !== 'function') {\r\n    window.Set = function(iterable) {\r\n      this._values = [];\r\n      if (iterable && typeof iterable.length === 'number') {\r\n        for (var i = 0; i < iterable.length; i += 1) this.add(iterable[i]);\r\n      }\r\n    };\r\n    window.Set.prototype.add = function(value) {\r\n      if (this._values.indexOf(value) === -1) this._values.push(value);\r\n      return this;\r\n    };\r\n    window.Set.prototype.has = function(value) {\r\n      return this._values.indexOf(value) !== -1;\r\n    };\r\n    window.Set.prototype.values = function() {\r\n      return this._values.slice();\r\n    };\r\n  }\r\n})();\r\n</script>\r\n"
