      "name": "teacher_preflight",
      "type": "HTML",
      "source": "<script>\r\n(function(){\r\n  function show(message){\r\n    var text = String(message || '').replace(/\\s+/g, ' ').trim();\r\n    if (!text) return;\r\n    var box = document.getElementById('teacherFatalError');\r\n    if (!box) return;\r\n    box.style.display = 'block';\r\n    box.textContent = '画面エラー: ' + text;\r\n  }\r\n\r\n  window.showFatalTeacherError = show;\r\n  window.__teacherPreflightLoaded = true;\r\n\r\n  window.onerror = function(message, source, lineno, colno){\r\n    var where = lineno ? ' @' + lineno + ':' + (colno || 0) : '';\r\n    show(String(message || 'unknown error') + where);\r\n    return false;\r\n  };\r\n\r\n  if (window.addEventListener) {\r\n    window.addEventListener('unhandledrejection', function(event){\r\n      var reason = event && event.reason;\r\n      show((reason && reason.message) || String(reason || 'promise rejection'));\r\n    });\r\n    window.addEventListener('load', function(){\r\n      setTimeout(function(){\r\n        if (typeof window.switchTab !== 'function') {\r\n          show('先生画面の操作スクリプトが読み込めていません。ブラウザが新しい構文に対応していない可能性があります。');\r\n        }\r\n      }, 800);\r\n    });\r\n  }\r\n})();\r\n</script>\r\n"
