      "source": "<!DOCTYPE html>\r\n<html lang=\"ja\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\r\n<title>先生画面</title>\r\n<?!= include('teacher_styles'); ?>\r\n</head>\r\n<body>\r\n\r\n<?!= include('teacher_nav'); ?>\r\n\r\n<div class=\"container\">\r\n<?!= include('teacher_section_status'); ?>\r\n<?!= include('teacher_section_curriculum'); ?>\r\n<?!= include('teacher_section_roster'); ?>\r\n<?!= include('teacher_section_prompts'); ?>\r\n<?!= include('teacher_section_help'); ?>\r\n<?!= include('teacher_section_logs'); ?>\r\n<?!= include('teacher_section_records'); ?>\r\n</div><!-- /container -->\r\n\r\n<?!= include('teacher_modal'); ?>\r\n<div id=\"teacherFatalError\" style=\"display:none;position:sticky;top:0;z-index:9999;margin:0 12px 12px;padding:12px 14px;border-radius:12px;background:#FFF3E0;color:#B71C1C;border:1px solid #FFCC80;font-weight:700;\"></div>\r\n<div class=\"toast-stack\" id=\"toastStack\" aria-live=\"polite\" aria-atomic=\"true\"></div>\r\n\r\n<?!= include('teacher_polyfills'); ?>\n<?!= include('teacher_preflight'); ?>\n<script>\nwindow.__TEACHER_BOOTSTRAP__ = <?!= bootstrapTeacherJson || 'null' ?>;\n</script>\n<?!= include('teacher_script_core_legacy'); ?>\n<?!= include('teacher_script_units_legacy'); ?>\n<?!= include('teacher_script_admin_legacy'); ?>\n<?!= include('teacher_script_reports_legacy'); ?>\r\n</body>\r\n</html>\r\n"
